using Microsoft.AspNetCore.Components.Authorization;
using sv_211ca09aee694c77a481802220022f6c;
using sv_211ca09aee694c77a481802220022f6c.Client.Pages;
using sv_211ca09aee694c77a481802220022f6c.Components;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents()
    .AddInteractiveWebAssemblyComponents();

builder.Services.AddScoped<AuthenticationStateProvider, HardcodedAuthenticationStateProvider>();
builder.Services.AddCascadingAuthenticationState();
builder.Services.AddAuthorization();
builder.Services.AddAuthenticationStateSerialization(options =>
    options.SerializeAllClaims = true);

using Microsoft.AspNetCore.Components.WebAssembly.Hosting;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

builder.Services.AddAuthorizationCore();
builder.Services.AddAuthenticationStateDeserialization();

await builder.Build().RunAsync();

